mapper.select:
select id, title, option_type, price, status
from options


        title like concat('%',#{title},'%')


        AND option_type = #{optionType}


        AND status = #{status}


order by create_time desc

mapper.update:
update options
title = #{title}, option_type = #{optionType} , price = #{price}, status = #{status}, update_id = #{updateId}, update_time = #{updateTime}
where id = #{id}
